code = """import json

# Load funding data
funding_path = locals()['var_functions.query_db:12']
with open(funding_path, 'r') as f:
    funding = json.load(f)

# Identify emergency/FEMA projects
emergency_projects = []
for record in funding:
    name = record['Project_Name'].lower()
    if 'fema' in name or 'emergency' in name or 'warning' in name or 'siren' in name:
        emergency_projects.append(record)

# Format results
results = []
results.append('PROJECTS RELATED TO EMERGENCY AND FEMA')
results.append('=' * 80)
results.append('')

for proj in emergency_projects:
    results.append('Project Name: %s' % proj['Project_Name'])
    results.append('Funding Source: %s' % proj['Funding_Source'])
    results.append('Amount: $%s' % '{:,}'.format(int(proj['Amount'])))
    results.append('Status: Unknown (requires document review)')
    results.append('')

result = '\n'.join(results)

print('__RESULT__:')
print(result)"""

